### 2. File: `services/tahfizh/engine.ts`
Engine utama yang menghitung selisih halaman dan baris secara akurat.

```typescript
import { AyahPointer, CalculationResult } from './types';
import { QURAN_FULL_MAP } from './quranFullData';

export class TahfizhEngine {
  private static readonly LINES_PER_PAGE = 15;

  /**
   * Normalisasi nama surah agar cocok dengan database (mengganti ‘ ’ ` ke ')
   */
  private static normalize(name: string): string {
    return name.replace(/[’‘`]/g, "'").trim();
  }

  /**
   * Menghitung jarak hafalan berdasarkan koordinat fisik Mushaf.
   * Logika: Menghitung total selisih baris (inclusive) lalu dikonversi ke Halaman & Sisa Baris.
   */
  static calculateRange(start: AyahPointer, end: AyahPointer): CalculationResult {
    const sKey = `${this.normalize(start.surah)}:${start.ayah}`;
    const eKey = `${this.normalize(end.surah)}:${end.ayah}`;

    let startPos = QURAN_FULL_MAP[sKey];
    let endPos = QURAN_FULL_MAP[eKey];

    // 1. Validasi Data
    if (!startPos || !endPos) {
      return { 
        pages: 0, 
        lines: 0, 
        juz: 0, 
        isPartial: true, 
        error: `Data ayat tidak ditemukan: ${!startPos ? sKey : eKey}` 
      };
    }

    // 2. Tentukan Arah Perhitungan
    // Jika posisi start secara fisik di Mushaf setelah end, kita balik agar selisih positif
    // Karena engine menghitung "berapa banyak yang dibaca", bukan urutan kurikulum
    let p1 = startPos;
    let p2 = endPos;

    if (p1.page > p2.page || (p1.page === p2.page && p1.line > p2.line)) {
      p1 = endPos;
      p2 = startPos;
    }

    // 3. Logika Hitung Sesuai Spesifikasi (Step 4 & 5)
    // Menghitung total baris yang dicakup secara inklusif
    // Rumus: (Selisih Halaman * 15) + (Baris Akhir - Baris Awal) + 1
    const totalLinesInclusive = ((p2.page - p1.page) * this.LINES_PER_PAGE) + (p2.line - p1.line) + 1;

    // 4. Konversi ke Format SDQ (Pages : Lines)
    // Pages = Berapa banyak halaman penuh 15 baris yang dicapai
    // Lines = Sisa baris (0-14)
    let finalPages = Math.floor(totalLinesInclusive / this.LINES_PER_PAGE);
    let finalLines = totalLinesInclusive % this.LINES_PER_PAGE;

    // Normalisasi tambahan jika sisa baris 0 maka halaman tetap
    // Contoh: 15 baris = 1 Halaman 0 Baris

    // Validasi Kasus Spesifik SDQ (Touched Pages)
    // Jika start dan end berbeda halaman, minimal pages adalah selisih halamannya
    const pageDiff = Math.abs(p2.page - p1.page);

    // Override untuk mengakomodasi "Touched Page" pada loncatan halaman
    // Jika total baris kecil tapi melintasi halaman, SDQ sering menghitung touched pages
    if (pageDiff > 0 && finalPages < pageDiff) {
        finalPages = pageDiff;
    }

    return {
      pages: finalPages,
      lines: finalLines,
      juz: endPos.juz,
      isPartial: false
    };
  }
}
```

### Penjelasan Logika & Validasi:

*   **Tanpa Estimasi**: Engine ini menggunakan `page` dan `line` dari `QURAN_FULL_MAP`. Jika kunci tidak ada, ia tidak menebak posisi.
*   **Akurasi 15 Baris**: Menggunakan konstanta `LINES_PER_PAGE = 15`.
*   **Arah Mundur**: Kode mendeteksi jika `start` memiliki nomor halaman lebih besar dari `end` (misal di Juz 30 yang urutannya terbalik) dan menukar pointernya secara otomatis untuk menghitung jarak fisik absolut.
*   **Normalisasi Baris**: Sisa baris selalu berada di rentang `0-14`. Jika mencapai 15, ia otomatis naik ke `pages`.

**Contoh Hasil Perhitungan:**
*   **An-Naba:1 (L3) ke An-Naba:24 (L12)**:
    *   Halaman sama (582).
    *   Selisih baris: `12 - 3 + 1 = 10`.
    *   Hasil: `0 Halaman, 10 Baris`.
*   **An-Naba:25 (582:L13) ke An-Naba:36 (583:L2)**:
    *   Halaman berbeda (582 & 583).
    *   Total Baris: `(1 * 15) + (2 - 13) + 1 = 15 - 11 + 1 = 5`.
    *   Halaman yang tersentuh: 1.
    *   Hasil: `1 Halaman, 5 Baris`.

